public void testLogin(String username, String password, boolean shouldSucceed) {
    setInputFieldValue("Username", username);
    setInputFieldValue("Password", password);
    clickButton("Login");

    if (shouldSucceed) {
        waitForPageLoading();
        assertTrue(isElementFound(By.id("dashboard")));
    } else {
        String error = getMessageBoxErrorText();
        assertFalse(error.isEmpty());
    }
}

public void fillPaymentDetails(String cardNumber, String expiry, String cvv) {
    setInputFieldValue("Card Number", cardNumber);
    setInputFieldValue("Expiry Date", expiry);
    setInputFieldValue("CVV", cvv);
    setCheckboxOn("Save card for future use");
}

public void filterTable(String searchTerm, String statusFilter) {
    searchTable(searchTerm);
    waitForPageLoading();
    clickButton("Filters");
    setDropdownValue("Status", statusFilter);
    clickDialogButton("Apply");
    waitForPageLoading();
}

