@Test
public void testKeyboardNavigation() {
    assertTrue(isInputFieldFound("Name"));
    assertTrue(isInputFieldFound("Email"));
    assertTrue(isDropdownFieldFound("Country"));
    assertTrue(isCheckboxFound("Terms"));
    assertTrue(isButtonFound("Submit"));

    // All interactive elements should be accessible
    assertFalse(isInputFieldDisabled("Name"));
    assertFalse(isDropdownFieldDisabled("Country"));
    assertFalse(isCheckboxDisabled("Terms"));
}

@Test
public void testPageLoadPerformance() {
    long startTime = System.currentTimeMillis();
    waitForPageLoading();
    long loadTime = System.currentTimeMillis() - startTime;

    assertTrue(loadTime < 5000, "Page should load within 5 seconds");
    assertTrue(isInputFieldFound("Name"));
    assertFalse(isSubmitButtonDisabled());
}
